# torch_ios: `regex` shim — forwards to stdlib `re`.
#
# The real `regex` package is a C extension that we haven't cross-compiled
# for iOS arm64. Most transformers / HF usage of `regex` only touches
# features that `re` supports (pattern compile, search, findall, split,
# sub, match flags like re.IGNORECASE). Re-export re's surface so
# `import regex` works.
#
# If something fails at runtime because it needs a feature only in the
# 3rd-party regex (named unicode categories like \p{L}, fuzzy matching,
# possessive quantifiers, subroutine calls), you'll get an `re.error`
# and we'll need a real regex build.

import re as _re
from re import *  # noqa: F401,F403

# Expose the module's __all__ + a few extras `regex` defines that `re` doesn't
# but are commonly imported.
__version__ = "2024.5.15-torch_ios-shim"

# The 3rd-party regex has these flags with different names.
# Map common aliases.
V1 = V0 = 0              # version flag, no-op
BESTMATCH = 0            # best-match-greedy flag, no-op
ENHANCEMATCH = 0
REVERSE = 0
POSIX = 0
WORD = 0
DEFAULT_VERSION = V0
B = _re.ASCII            # WORD boundary "ascii" alias
F = BESTMATCH            # fuzzy

# Some transformers code does `regex.compile(...).fullmatch(...)` — re supports it.
# Some uses `regex.findall(..., overlapped=True)` — re doesn't. Wrap to ignore.
_orig_findall = _re.findall
def findall(pattern, string, flags=0, pos=None, endpos=None, overlapped=False, concurrent=None, timeout=None):
    return _orig_findall(pattern, string, flags=flags)

_orig_finditer = _re.finditer
def finditer(pattern, string, flags=0, pos=None, endpos=None, overlapped=False, concurrent=None, timeout=None):
    return _orig_finditer(pattern, string, flags=flags)

_orig_sub = _re.sub
def sub(pattern, repl, string, count=0, flags=0, pos=None, endpos=None, concurrent=None, timeout=None):
    return _orig_sub(pattern, repl, string, count=count, flags=flags)

_orig_search = _re.search
def search(pattern, string, flags=0, pos=None, endpos=None, partial=False, concurrent=None, timeout=None):
    return _orig_search(pattern, string, flags=flags)

_orig_match = _re.match
def match(pattern, string, flags=0, pos=None, endpos=None, partial=False, concurrent=None, timeout=None):
    return _orig_match(pattern, string, flags=flags)

_orig_fullmatch = _re.fullmatch
def fullmatch(pattern, string, flags=0, pos=None, endpos=None, partial=False, concurrent=None, timeout=None):
    return _orig_fullmatch(pattern, string, flags=flags)

_orig_split = _re.split
def split(pattern, string, maxsplit=0, flags=0, concurrent=None, timeout=None):
    return _orig_split(pattern, string, maxsplit=maxsplit, flags=flags)
